import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DPTLmtS5.js";var i=JSON.parse(`{"title":"Element Change","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/element-change.md","filePath":"documentation/field-types/element-change.md","lastUpdated":1770573358000}`),a={name:`documentation/field-types/element-change.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="element-change" tabindex="-1">Element Change <a class="header-anchor" href="#element-change" aria-label="Permalink to “Element Change”">​</a></h1><p>On which element it is used, if that element <strong>changes</strong> then this Field Type returns <strong>true</strong>.</p><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to “Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th></tr></thead><tbody><tr><td><a href="#which-dom-mutations-should-be-reported-to">Which DOM mutations should be reported to</a></td></tr><tr><td><a href="#timeout-to-check-element-change">Timeout to Check Element Change (Seconds)</a></td></tr><tr><td><a href="#whether-the-element-is-modified-or-not-do-it-in-the-background-process">Whether the element is modified or not, do it in the background process</a></td></tr><tr><td><a href="#do-you-want-to-click-on-an-element">Do you want to click on an element?</a></td></tr><tr><td><a href="#enter-element-selector-xpath">Enter Element Selector/Xpath</a></td></tr></tbody></table><h2 id="which-dom-mutations-should-be-reported-to" tabindex="-1">Which DOM mutations should be reported to <a class="header-anchor" href="#which-dom-mutations-should-be-reported-to" aria-label="Permalink to “Which DOM mutations should be reported to”">​</a></h2><p>The part in which the change is taking place in the element is given here.</p><ul><li>attributes</li><li>childList</li><li>characterData</li><li>subtree</li></ul><h2 id="timeout-to-check-element-change" tabindex="-1">Timeout to Check Element Change <a class="header-anchor" href="#timeout-to-check-element-change" aria-label="Permalink to “Timeout to Check Element Change”">​</a></h2><p>After completion of the time given in this, this field returns false. In this the time is given in <strong>seconds</strong>.</p><h2 id="whether-the-element-is-modified-or-not-do-it-in-the-background-process" tabindex="-1">Whether the element is modified or not, do it in the background process <a class="header-anchor" href="#whether-the-element-is-modified-or-not-do-it-in-the-background-process" aria-label="Permalink to “Whether the element is modified or not, do it in the background process”">​</a></h2><p>By default it waits for the field element to change and the filler does not move forward until something changes in the element. But after turning on this option, it checks the process of element change in the <strong>background</strong> and Filler executes the next fields.</p><details class="details custom-block"><summary>After turning on this option, it checks the element change in the background, then how to check whether the element has changed or not?</summary><p>In which next field you want to check whether the element has changed, you can use the option given below in the settings of the field in which you want to check.</p><p><a href="/documentation/form-fields/field-settings.html#wait-until-the-response-status-of-the-given-element-change-fields-comes">Wait until the response status of the given element change fields comes</a></p></details><h2 id="do-you-want-to-click-on-an-element" tabindex="-1">Do you want to click on an element? <a class="header-anchor" href="#do-you-want-to-click-on-an-element" aria-label="Permalink to “Do you want to click on an element?”">​</a></h2><p>This is a <strong>switch field</strong> that allows you to trigger a click action on a specific element before monitoring for changes. When enabled, the extension will click on the specified element and then wait for the DOM mutations to occur.</p><p>This is useful when:</p><ul><li>You need to trigger an action (like clicking a button) that causes the element to change</li><li>The element change only occurs after user interaction</li><li>You want to automate the click and monitor the result in a single field</li></ul><h2 id="enter-element-selector-xpath" tabindex="-1">Enter Element Selector/Xpath <a class="header-anchor" href="#enter-element-selector-xpath" aria-label="Permalink to “Enter Element Selector/Xpath”">​</a></h2><p>When the <strong>&quot;Do you want to click on an element?&quot;</strong> option is enabled, this field becomes available. Here you can specify the target element that should be clicked using either:</p><ul><li><strong>CSS Selector</strong>: e.g., <code>#submitButton</code>, <code>.action-btn</code>, <code>button[type=&quot;submit&quot;]</code></li><li><strong>XPath</strong>: e.g., <code>//button[@id=&#39;submitButton&#39;]</code>, <code>//div[@class=&#39;action-btn&#39;]</code></li></ul><p>The extension will locate this element and click it before starting to monitor the element changes specified in the main field configuration.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to “Tips”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>If using this field type then turn off this field setting <a href="/documentation/form-fields/field-settings.html#do-not-fill-the-status-color-element-of-this-field">Do not fill the Status Color, element of this field</a>.</p></div><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>If the element changes before the extension&#39;s Element Change field type action takes place, the action on this field type will not be completed and your filler will also stop.</p></div>`,23)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};